  5	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
  6	import { getMemorySize } from '@kubevirt-utils/components/CPUMemoryModal/utils/CpuMemoryUtils';
  7	import { getMemory } from '@kubevirt-utils/resources/vm';
  8	import { isEmpty } from '@kubevirt-utils/utils/utils';
  9	import { PrometheusEndpoint, usePrometheusPoll } from '@openshift-console/dynamic-plugin-sdk';
 10	import {
 11	  Chart,
 12	  ChartArea,
 13	  ChartAxis,
 14	  ChartGroup,
 15	  ChartThreshold,
 16	  ChartVoronoiContainer,
 17	} from '@patternfly/react-charts';
 18	import chart_color_black_200 from '@patternfly/react-tokens/dist/esm/chart_color_black_200';
 19	import chart_color_blue_300 from '@patternfly/react-tokens/dist/esm/chart_color_blue_300';
 20	import chart_color_orange_300 from '@patternfly/react-tokens/dist/esm/chart_color_orange_300';
 21	import useDuration from '@virtualmachines/details/tabs/metrics/hooks/useDuration';
 22	
 23	import { tickLabels } from '../ChartLabels/styleOverrides';
 24	import ComponentReady from '../ComponentReady/ComponentReady';
 25	import useResponsiveCharts from '../hooks/useResponsiveCharts';
 26	import { getUtilizationQueries } from '../utils/queries';
 27	import {
 28	  findMaxYValue,
 29	  MILLISECONDS_MULTIPLIER,
 30	  queriesToLink,
 31	  tickFormat,
 32	  TICKS_COUNT,
 33	} from '../utils/utils';
 34	
 35	type MemoryThresholdChartProps = {
 36	  vmi: V1VirtualMachineInstance;
 37	};
 38	
 39	const MemoryThresholdChart: FC<MemoryThresholdChartProps> = ({ vmi }) => {
 40	  const { currentTime, duration, timespan } = useDuration();
 41	  const queries = useMemo(() => getUtilizationQueries({ duration, obj: vmi }), [vmi, duration]);
 42	  const { height, ref, width } = useResponsiveCharts();
 43	
 44	  const memory = getMemorySize(getMemory(vmi));
 45	
 46	  const [data] = usePrometheusPoll({
 47	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
 48	    endTime: currentTime,
 49	    namespace: vmi?.metadata?.namespace,
 50	    query: queries?.MEMORY_USAGE,
 51	    timespan,
 52	  });
 53	
 54	  const prometheusMemoryData = data?.data?.result?.[0]?.values;
 55	  const memoryAvailableBytes = xbytes.parseSize(`${memory?.size} ${memory?.unit}B`);
 56	
 57	  const chartData = prometheusMemoryData?.map(([x, y]) => {
 58	    return { name: 'Memory used', x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) };
 59	  });
 60	
 61	  const thresholdLine = new Array(chartData?.length || 0).fill(0).map((_, index) => ({
 62	    name: 'Memory available',
 63	    x: chartData?.[index]?.x,
 64	    y: memoryAvailableBytes,
 65	  }));
 66	
 67	  const isReady = !isEmpty(chartData) || !isEmpty(thresholdLine);
 68	  const linkToMetrics = queriesToLink(queries?.MEMORY_USAGE);
 69	  const yMax = findMaxYValue(thresholdLine);
 70	  return (
 71	    <ComponentReady isReady={isReady} linkToMetrics={linkToMetrics}>
 72	      <div className="util-threshold-chart" ref={ref}>
 73	        <Link to={linkToMetrics}>
 74	          <Chart
 75	            containerComponent={
 76	              <ChartVoronoiContainer
 77	                labels={({ datum }) => {
 78	                  return `${datum?.name}: ${xbytes(datum?.y, {
 79	                    fixed: 2,
 80	                    iec: true,
 81	                  })}`;
 82	                }}
 83	                constrainToVisibleArea
 84	              />
 85	            }
 86	            domain={{
 87	              x: [currentTime - timespan, currentTime],
 88	            }}
 89	            height={height}
 90	            padding={{ bottom: 35, left: 70, right: 35, top: 35 }}
 91	            scale={{ x: 'time', y: 'linear' }}
 92	            width={width}
 93	          >
 94	            <ChartAxis
 95	              style={{
 96	                tickLabels: { padding: 2, ...tickLabels },
 97	                ticks: { stroke: 'transparent' },
 98	              }}
 99	              axisComponent={<></>}
100	              tickCount={TICKS_COUNT}
101	              tickFormat={tickFormat(duration, currentTime)}
102	            />
103	            <ChartAxis
104	              style={{
105	                grid: {
106	                  stroke: chart_color_black_200.value,
107	                },
108	                tickLabels,
109	              }}
110	              dependentAxis
111	              tickFormat={(tick: number) => xbytes(tick, { fixed: 2, iec: true })}
112	              tickValues={[0, yMax]}
113	            />
114	            <ChartGroup>
115	              <ChartArea
116	                style={{
117	                  data: {
118	                    stroke: chart_color_blue_300.value,
119	                  },
120	                }}
121	                data={chartData}
122	              />
123	            </ChartGroup>
124	            <ChartThreshold
125	              style={{
126	                data: {
127	                  stroke: chart_color_orange_300.value,
128	                  strokeDasharray: 10,
129	                },
130	              }}
131	              data={thresholdLine}
132	            />
133	          </Chart>
134	        </Link>
135	      </div>
136	    </ComponentReady>
137	  );
138	};
139	
140	export default MemoryThresholdChart;

